1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { fireEvent, screen, waitFor } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
5	import * as api from "@/lib/api/client";
6	import type { Market } from "@/lib/api/types";
7	
8	vi.mock("@/lib/api/client");
9	
10	const accountId = "acct-resolver";
11	
12	const makeMarket = (overrides: Partial<Market> = {}): Market => ({
13	  id: "m1",
14	  title: "Test Market",
15	  description: "Test",
16	  variableId: "var1",
17	  status: "active",
18	  outcomes: [
19	    { id: "yes", name: "Yes" },
20	    { id: "no", name: "No" },
21	  ],
22	  marginals: { yes: 0.6, no: 0.4 },
23	  liquidity: 1000,
24	  volume: 500,
25	  created_at: "2026-01-01T00:00:00Z",
26	  expires_at: "2026-12-31T23:59:59Z",
27	  ...overrides,
28	});
29	
30	beforeEach(() => {
